var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"현대 판타지의 초능력자들과 이세계의 침략자들의 대결……?","JPN":"現代ファンタジーの超能力者と、異世界の侵略者との対決……？","ENG":"A battle between modern-fantasy psychics and otherworldly invaders...?","TWN":"現代奇幻的超能力者與異界侵略者的對決……？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"이거 진짜 스트리트 카운터의 설정 그대로네요? 어쩐지 아트도 비슷한 것 같고?","JPN":"これ、本当にストリート・カウンターの設定そのまんまですね。なんだかアートも似てますし。","ENG":"It’s pretty much the same setting as Street Counter. The artwork looks awfully similar too.","TWN":"真的完全是街頭制裁者的故事設定欸？怎麼好像連美術也都差不多？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"당연한 거 아이가? 스트리트 카운터의 리소스를 바탕으로 제작했으니까.","JPN":"当たり前やん。ストリート・カウンターのリソースを基に作ったんやから。","ENG":"Of course it is. We made the thing from the resources of Street Counter.","TWN":"這是當然的唄！就是以街頭制裁者的素材為範本去製作的唄。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그, 그래도 되는 거예요?","JPN":"そ、それでも大丈夫なんですか？","ENG":"Y-you’re allowed to do that?","TWN":"這樣…沒問題嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응응, 물론이지. 쌤이 써도 된다고 했으니까 아무 문제없다!","JPN":"うんうん、もちろん。先生が使っていいって言ったんやから、何の問題もあらへん！","ENG":"Of course, we are. Teach said we could use them freely!","TWN":"嗯嗯，沒問題，是老師說可以用的，放心唄！"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"자, 잠깐! 그러고 보니까 이거 격투 게임이 아니잖아요!?","JPN":"ちょ、ちょっと待ってください！　そういえばこれ格ゲーじゃないじゃないですか！？","ENG":"W-wait a second! But this isn’t a fighting game!","TWN":"等…等等！這根本不是格鬥遊戲吧！？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 이래서 눈치 빠른 꼬맹이는 싫다 아이가.","JPN":"へへっ、これだから勘のいいじゃりんこは嫌いやねん。","ENG":"Heh, I hate perceptive brats like you...","TWN":"嘿嘿，我最討厭像你這種敏銳的小朋友。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"맞다. 격투 게임의 리소스를 빌려 쓰긴 했지만, 카운터즈 사가는 격투 게임은 아니거든.","JPN":"そうや。格ゲーのリソースを借りてるけど、カウンターズ・サーガは格ゲーやない。","ENG":"Ya ain’t wrong. Despite usin’ resources from a fighting game, Counters Saga ain’t one.","TWN":"沒錯，雖然是借用格鬥遊戲的素材，但制裁者傳奇本身不是格鬥遊戲。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그럼요?","JPN":"それじゃあ？","ENG":"What is it, then?","TWN":"那是什麼？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"벨트 스크롤 같은…… 아니, <color=#ffd34c>라인 디펜스</color>라고 들어는 봤나?","JPN":"ベルトスクロールみたいな……いや、<color=#ffd34c>ラインディフェンス</color>って聞いたことあるか？","ENG":"It’s a belt scroll action... No, rather <color=#ffd34c>line defense</color>, maybe?","TWN":"類似帶狀卷軸……不對，你聽過<color=#ffd34c>防線防守</color>嗎？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"벨트 스크롤은 알겠는데…… 라인 디펜스는 뭐에요? 처음 들어 보는데?","JPN":"ベルトスクロールは知ってますけど……ラインディフェンスって何ですか？　初めて聞きました。","ENG":"I know what belt scroll action is, but line defense...? What’s that? I never heard of it before.","TWN":"帶狀捲軸我聽過……防守防線是什麼？第一次聽到？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 걱정말그라. 내 가르쳐 줄게. 마우스 좀 빌려도.","JPN":"へへっ、心配あらへん。ウチが教えてあげるわ。ちょっとマウス貸してみ？","ENG":"Heh, don’t fret. I’ll teach ya. Fetch that mouse for me, will ya?","TWN":"嘿嘿，沒問題的，我教你唄。滑鼠借一下。"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"앗…… 방금 손 닿았는데…….","JPN":"あっ……今手が触れた……","ENG":"Ah... She touched my hand...","TWN":"唔……剛剛有碰到手……"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"여기 하단의 캐릭터 얼굴들 보이제?","JPN":"ここ、下にキャラの顔が見えるやろ？","ENG":"Ya see these characters at the bottom?","TWN":"有看到下面角色的臉唄？"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"출격 자원의 코스트에 맞는 유닛을 골라가, 이렇게 전장에 배치하는 기다!","JPN":"出撃資源のコストに合うユニットを選んで、こうやって戦場に配置するんやで！","ENG":"Choose units that match the cost of Deployment Resources and deploy them on the battlefield, like this!","TWN":"配合出擊資源選擇角色，然後像這樣布署到戰場上！"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}}]`);export{e as default};